Feign客户端@FeignClient(name = &quot;order-service&quot;, fallbackFactory = OrderClientFallbackFactory.class)public interface OrderClient &#123;    @GetMapping(&quot;/order/user/&#123;userId&#125;&quot;)    Result&lt;List&lt;OrderVO&gt;&gt; getByUserId(@PathVariable(&quot;userId&quot;) Long userId);&#125;@Component@Slf4jpublic class OrderClientFallbackFactory implements FallbackFactory&lt;OrderClient&gt; &#123;    @Override    public OrderClient create(Throwable cause) &#123;        log.error(&quot;订单服务调用失败: &#123;&#125;&quot;, cause.getMessage());        return userId -&gt; Result.success(Collections.emptyList());    &#125;&#125;

启动类@EnableFeignClients@EnableDiscoveryClient@SpringBootApplicationpublic class UserServiceApplication &#123;    public static void main(String[] args) &#123;        SpringApplication.run(UserServiceApplication.class, args);    &#125;&#125;

订单服务Feign客户端@FeignClient(name = &quot;product-service&quot;, fallbackFactory = ProductClientFallbackFactory.class)public interface ProductClient &#123;    @GetMapping(&quot;/product/&#123;id&#125;&quot;)    Result&lt;ProductVO&gt; getById(@PathVariable(&quot;id&quot;) Long id);    @PostMapping(&quot;/product/deduct&quot;)    Result&lt;Void&gt; deduct(@RequestBody DeductRequest request);&#125;@FeignClient(name = &quot;user-service&quot;, fallbackFactory = UserClientFallbackFactory.class)public interface UserClient &#123;    @GetMapping(&quot;/user/&#123;id&#125;&quot;)    Result&lt;UserVO&gt; getById(@PathVariable(&quot;id&quot;) Long id);&#125;

订单服务实现@Service@RequiredArgsConstructor@Slf4jpublic class OrderServiceImpl implements OrderService &#123;    private final OrderMapper orderMapper;    private final ProductClient productClient;    private final UserClient userClient;    @Override    @SentinelResource(value = &quot;createOrder&quot;, fallback = &quot;createOrderFallback&quot;)    public OrderVO createOrder(OrderCreateDTO dto) &#123;        // 1. 查询用户        Result&lt;UserVO&gt; userResult = userClient.getById(dto.getUserId());        if (userResult == null || !userResult.isSuccess()) &#123;            throw new BusinessException(&quot;用户不存在&quot;);        &#125;        // 2. 查询商品        Result&lt;ProductVO&gt; productResult = productClient.getById(dto.getProductId());        if (productResult == null || !productResult.isSuccess()) &#123;            throw new BusinessException(&quot;商品不存在&quot;);        &#125;        // 3. 扣减库存        DeductRequest deductReq = new DeductRequest(dto.getProductId(), dto.getQuantity());        Result&lt;Void&gt; deductResult = productClient.deduct(deductReq);        if (deductResult == null || !deductResult.isSuccess()) &#123;            throw new BusinessException(&quot;库存不足&quot;);        &#125;        // 4. 创建订单        Order order = new Order();        order.setUserId(dto.getUserId());        order.setProductId(dto.getProductId());        order.setQuantity(dto.getQuantity());        order.setAmount(productResult.getData().getPrice().multiply(            BigDecimal.valueOf(dto.getQuantity()));        order.setStatus(OrderStatus.WAIT_PAY);        orderMapper.insert(order);        return OrderVO.build(order);    &#125;    public OrderVO createOrderFallback(OrderCreateDTO dto, Throwable ex) &#123;        log.error(&quot;创建订单降级: &#123;&#125;&quot;, ex.getMessage());        throw new BusinessException(&quot;系统繁忙，请稍后重试&quot;);    &#125;&#125;

公共模块// 统一返回结果@Data@Builderpublic class Result&lt;T&gt; &#123;    private int code;    private String message;    private T data;    public static &lt;T&gt; Result&lt;T&gt; success(T data) &#123;        return Result.&lt;T&gt;builder().code(200).message(&quot;success&quot;).data(data).build();    &#125;    public static &lt;T&gt; Result&lt;T&gt; fail(String message) &#123;        return Result.&lt;T&gt;builder().code(500).message(message).build();    &#125;&#125;// 全局异常处理@RestControllerAdvicepublic class GlobalExceptionHandler &#123;    @ExceptionHandler(BusinessException.class)    public Result&lt;Void&gt; handleBusiness(BusinessException e) &#123;        return Result.fail(e.getMessage());    &#125;    @ExceptionHandler(Exception.class)    public Result&lt;Void&gt; handleException(Exception e) &#123;        log.error(&quot;系统异常&quot;, e);        return Result.fail(&quot;系统异常&quot;);    &#125;&#125;

面试高频问题1. SpringCloud微服务架构包含哪些组件？注册中心(Nacos)、配置中心(Nacos)、网关(Gateway)、服务调用(OpenFeign)、负载均衡(LoadBalancer)、熔断降级(Sentinel)。
2. Gateway的作用？统一入口、路由转发、身份认证、限流熔断、日志监控。所有外部请求先经过Gateway再路由到具体服务。
3. 微服务之间如何通信？同步调用：OpenFeign（推荐）。异步通信：MQ。选择：需要实时响应用Feign，不需要实时用MQ。
最佳实践
Gateway做统一入口：认证、限流、路由
Feign做服务调用：声明式，简洁优雅
Fallback兜底：服务降级不影响主流程
公共模块抽离：Result、异常处理、工具类
Nacos管理配置：动态刷新不重启

总结SpringCloud + Nacos是Java微服务的主流方案。2023年从零搭建后，核心认知是：Nacos同时做注册中心和配置中心，Gateway做统一入口，OpenFeign做服务调用，Sentinel做熔断降级。微服务不是拆分越细越好，而是按业务域合理拆分。

前言做订单系统时，下单后要发短信、加积分、发推送，最初全写在一个方法里，代码越来越臃肿。后来学会Spring事件机制，下单只发事件，各模块各自监听，代码瞬间清爽。2023年深入源码后，对事件机制有了更深的理解。 观察者模式Spring事件机制本质是观察者模式的实现： 主题(Subject) → ApplicationEventPublisher观察者(Observer) → ApplicationListener事件(Event) → ApplicationEvent发布者不需要知道谁在监听，监听者也不需要知道谁在发布
Spring事件核心组件// 1. 事件：ApplicationEventpublic abstract class ApplicationEvent extends EventObject &#123; private final long timestamp; public ApplicationEvent(Object source) &#123; super(source); this.timestamp = System.currentTimeMillis(); &#125;&#125;// 2. 发布者：ApplicationEventPublisher@FunctionalInterfacepublic interface ApplicationEventPublisher &#123; default void publishEvent(ApplicationEvent event) &#123; publishEvent((Object) event); &#125; void publishEvent(Object event);&#125;// 3. 监听者：ApplicationListener@FunctionalInterfacepublic interface ApplicationListener&lt;E extends ApplicationEvent&gt; extends EventListener &#123; void onApplicationEvent(E event);&#125;// 4. 广播器：ApplicationEventMulticaster// 负责管理监听者并广播事件
自定义事件实战1. 定义事件// 订单创建事件public class OrderCreatedEvent extends ApplicationEvent &#123; private final Long orderId; private final Long userId; private final BigDecimal amount; public OrderCreatedEvent(Object source, Long orderId, Long userId, BigDecimal amount) &#123; super(source); this.orderId = orderId; this.userId = userId; this.amount = amount; &#125; // getter&#125;
2. 发布事件@Service@RequiredArgsConstructor@Slf4jpublic class OrderService &#123; private final ApplicationEventPublisher eventPublisher; private final OrderMapper orderMapper; @Transactional public Order createOrder(OrderDTO dto) &#123; Order order = new Order(); // ... 创建订单 orderMapper.insert(order); // 发布事件（事务提交后处理） eventPublisher.publishEvent( new OrderCreatedEvent(this, order.getId(), order.getUserId(), order.getAmount())); log.info(&quot;订单创建成功: orderId=&#123;&#125;&quot;, order.getId()); return order; &#125;&#125;
3. 监听事件// 方式1：实现ApplicationListener接口@Component@Slf4jpublic class SmsListener implements ApplicationListener&lt;OrderCreatedEvent&gt; &#123; @Override public void onApplicationEvent(OrderCreatedEvent event) &#123; log.info(&quot;发送短信通知: orderId=&#123;&#125;&quot;, event.getOrderId()); // 发送短信 &#125;&#125;// 方式2：@EventListener注解（推荐）@Component@Slf4jpublic class PointsListener &#123; @EventListener public void onOrderCreated(OrderCreatedEvent event) &#123; log.info(&quot;增加积分: userId=&#123;&#125;, amount=&#123;&#125;&quot;, event.getUserId(), event.getAmount()); // 增加积分 &#125;&#125;// 方式3：@EventListener支持SpEL条件@Component@Slf4jpublic class VipPointsListener &#123; @EventListener(condition = &quot;#event.amount &gt; 100&quot;) public void onOrderCreated(OrderCreatedEvent event) &#123; log.info(&quot;大额订单额外积分: amount=&#123;&#125;&quot;, event.getAmount()); &#125;&#125;
事务绑定事件问题：事件在事务提交前执行@Transactionalpublic Order createOrder(OrderDTO dto) &#123; orderMapper.insert(order); eventPublisher.publishEvent(new OrderCreatedEvent(this, order.getId())); // 如果事务回滚，事件已经发出去了！ // 监听者可能处理了一个不存在的订单&#125;
解决：@TransactionalEventListener@Component@Slf4jpublic class PointsListener &#123; // 在事务提交后执行 @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT) public void onOrderCreated(OrderCreatedEvent event) &#123; log.info(&quot;事务已提交，增加积分: orderId=&#123;&#125;&quot;, event.getOrderId()); // 此时订单已经持久化，可以安全处理 &#125;&#125;// 四种阶段：// BEFORE_COMMIT：事务提交前（默认）// AFTER_COMMIT：事务提交后（最常用）// AFTER_ROLLBACK：事务回滚后// AFTER_COMPLETION：事务完成后（提交或回滚）
注意：@TransactionalEventListener在无事务环境下不生效// 如果调用方法没有事务，@TransactionalEventListener不会触发// 解决：同时加@EventListener作为兜底@Component@Slf4jpublic class PointsListener &#123; @EventListener @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT) public void onOrderCreated(OrderCreatedEvent event) &#123; // 有事务：AFTER_COMMIT执行 // 无事务：@EventListener兜底执行 &#125;&#125;
异步事件监听// 默认事件监听是同步的，发布者会等待所有监听者执行完// 如果某个监听者耗时长，会阻塞发布者// 解决：@Async + 线程池@Component@Slf4jpublic class AsyncNotificationListener &#123; @Async(&quot;taskExecutor&quot;) @EventListener public void onOrderCreated(OrderCreatedEvent event) &#123; // 异步执行，不阻塞发布者 log.info(&quot;异步发送通知: orderId=&#123;&#125;&quot;, event.getOrderId()); emailService.sendOrderConfirm(event.getUserId(), event.getOrderId()); pushService.pushOrderCreated(event.getUserId()); &#125;&#125;
Spring内置事件
事件 触发时机
ContextRefreshedEvent ApplicationContext刷新完成
ContextStartedEvent ApplicationContext启动
ContextStoppedEvent ApplicationContext停止
ContextClosedEvent ApplicationContext关闭
RequestHandledEvent Web请求处理完成
实战：容器启动后初始化@Component@Slf4jpublic class StartupInitializer &#123; @EventListener(ContextRefreshedEvent.class) public void onStartup() &#123; log.info(&quot;Spring容器启动完成，开始初始化&quot;); // 加载缓存、预热数据、启动定时任务 cacheService.warmUp(); &#125;&#125;
事件机制源码分析事件发布流程// AbstractApplicationContext.publishEvent()public void publishEvent(Object event) &#123; // 委托给ApplicationEventMulticaster广播 getApplicationEventMulticaster().multicastEvent( applicationEvent, eventType);&#125;// SimpleApplicationEventMulticaster.multicastEvent()public void multicastEvent(ApplicationEvent event, ResolvableType eventType) &#123; // 获取所有匹配的监听者 for (ApplicationListener&lt;?&gt; listener : getApplicationListeners(event, type)) &#123; Executor executor = getTaskExecutor(); if (executor != null) &#123; // 有线程池 → 异步执行 executor.execute(() -&gt; invokeListener(listener, event)); &#125; else &#123; // 无线程池 → 同步执行 invokeListener(listener, event); &#125; &#125;&#125;
@EventListener注册原理// EventListenerMethodProcessor// 在Bean初始化后，扫描@EventListener注解，注册为ApplicationListener@Overridepublic void afterSingletonsInstantiated() &#123; // 遍历所有Bean for (String beanName : beanNames) &#123; Class&lt;?&gt; type = beanFactory.getType(beanName); // 扫描@EventListener注解的方法 processBean(beanName, type); &#125;&#125;private void processBean(String beanName, Class&lt;?&gt; type) &#123; // 为每个@EventListener方法创建ApplicationListener适配器 // 注册到ApplicationEventMulticaster&#125;
实战：事件驱动的订单系统// 事件定义public class OrderCreatedEvent extends ApplicationEvent &#123; private final Long orderId; private final Long userId; private final BigDecimal amount;&#125;public class OrderPaidEvent extends ApplicationEvent &#123; private final Long orderId; private final BigDecimal amount;&#125;public class OrderCancelledEvent extends ApplicationEvent &#123; private final Long orderId; private final String reason;&#125;// 订单服务：只负责核心逻辑@Service@RequiredArgsConstructor@Slf4jpublic class OrderService &#123; private final OrderMapper orderMapper; private final ApplicationEventPublisher eventPublisher; @Transactional public Order createOrder(OrderDTO dto) &#123; Order order = new Order(); // ... 创建订单 orderMapper.insert(order); eventPublisher.publishEvent(new OrderCreatedEvent(this, order.getId(), order.getUserId(), order.getAmount())); return order; &#125; @Transactional public void payOrder(Long orderId) &#123; Order order = orderMapper.selectById(orderId); order.setStatus(OrderStatus.PAID); orderMapper.updateById(order); eventPublisher.publishEvent(new OrderPaidEvent(this, orderId, order.getAmount())); &#125; @Transactional public void cancelOrder(Long orderId, String reason) &#123; Order order = orderMapper.selectById(orderId); order.setStatus(OrderStatus.CANCELLED); orderMapper.updateById(order); eventPublisher.publishEvent(new OrderCancelledEvent(this, orderId, reason)); &#125;&#125;// 积分监听@Component @Slf4jpublic class PointsEventListener &#123; @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT) public void onOrderPaid(OrderPaidEvent event) &#123; pointsService.addPoints(event.getOrderId(), event.getAmount()); &#125;&#125;// 通知监听@Component @Slf4jpublic class NotificationEventListener &#123; @Async(&quot;taskExecutor&quot;) @EventListener public void onOrderCreated(OrderCreatedEvent event) &#123; smsService.sendOrderConfirm(event.getUserId(), event.getOrderId()); &#125; @Async(&quot;taskExecutor&quot;) @EventListener public void onOrderCancelled(OrderCancelledEvent event) &#123; smsService.sendCancelNotice(event.getUserId(), event.getOrderId()); &#125;&#125;// 库存监听@Component @Slf4jpublic class StockEventListener &#123; @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT) public void onOrderCreated(OrderCreatedEvent event) &#123; stockService.deductByOrder(event.getOrderId()); &#125; @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT) public void onOrderCancelled(OrderCancelledEvent event) &#123; stockService.releaseByOrder(event.getOrderId()); &#125;&#125;
面试高频问题1. Spring事件机制的原理？基于观察者模式，通过ApplicationEventPublisher发布事件，ApplicationEventMulticaster广播给所有匹配的ApplicationListener。@EventListener是注解驱动的便捷方式。 2. @EventListener和@TransactionalEventListener的区别？@TransactionalEventListener绑定事务阶段，只在事务特定阶段（如AFTER_COMMIT）执行；@EventListener立即执行。事务回滚时@TransactionalEventListener不会触发。 3. 事件监听是同步还是异步？默认同步。加@Async注解可异步执行，需要配置线程池。 最佳实践 业务解耦用事件：下单后的短信、积分、推送等用事件驱动 事务相关用@TransactionalEventListener：确保事务提交后再处理 耗时操作用@Async：避免阻塞发布者 事件对象要轻量：只传ID，监听者自己查数据 注意事件顺序：@Order注解控制监听者执行顺序
总结Spring事件机制是业务解耦的利器。2023年深入理解后，核心认知是：事件驱动让核心逻辑与副作用解耦，@TransactionalEventListener保证数据一致性，@Async保证性能。订单系统从”一个方法500行”到”核心逻辑+5个监听器”，代码可维护性质的飞跃。

前言线上一次事故让我刻骨铭心：转账接口加了@Transactional，但部分数据没回滚，导致账目不一致。排查后发现是同类方法调用导致事务失效。这次事故让我花了一周时间，把Spring事务失效的所有场景全部梳理一遍，再也不踩坑。 事务失效的根本原因Spring事务基于AOP动态代理实现，本质是通过对目标对象生成代理对象，在代理对象中拦截方法调用，添加事务管理逻辑。一旦绕过了代理对象，事务就失效了。 正常调用：调用方 → 代理对象 → 事务增强 → 目标方法失效调用：调用方 → 目标对象 → 目标方法（无事务增强）
场景一：同类方法调用这是最常见的失效场景，也是我线上踩坑的原因。 失效代码@Servicepublic class UserService &#123; @Autowired private UserMapper userMapper; @Autowired private AccountMapper accountMapper; public void transfer(Long fromId, Long toId, BigDecimal amount) &#123; // 直接调用同类方法，事务失效！ this.doTransfer(fromId, toId, amount); &#125; @Transactional public void doTransfer(Long fromId, Long toId, BigDecimal amount) &#123; accountMapper.deduct(fromId, amount); accountMapper.add(toId, amount); // 如果这里抛异常，不会回滚！ &#125;&#125;
原因分析// 外部调用transfer()时，走的是代理对象// 但transfer()内部调用this.doTransfer()，this是目标对象本身// 目标对象直接调用自己的方法，绕过了代理，事务增强不会生效// 调用链路：// Controller → 代理对象.transfer() → 目标对象.this.doTransfer()// ↑ 没有经过代理！
解决方案// 方案1：注入自身代理（推荐）@Servicepublic class UserService &#123; @Autowired @Lazy // 解决循环依赖 private UserService self; public void transfer(Long fromId, Long toId, BigDecimal amount) &#123; self.doTransfer(fromId, toId, amount); // 通过代理调用 &#125; @Transactional public void doTransfer(Long fromId, Long toId, BigDecimal amount) &#123; // 事务生效 &#125;&#125;// 方案2：AopContext获取当前代理@Servicepublic class UserService &#123; public void transfer(Long fromId, Long toId, BigDecimal amount) &#123; UserService proxy = (UserService) AopContext.currentProxy(); proxy.doTransfer(fromId, toId, amount); &#125; @Transactional public void doTransfer(Long fromId, Long toId, BigDecimal amount) &#123; // 事务生效 &#125;&#125;// 注意：AopContext方式需要在启动类加上：// @EnableAspectJAutoProxy(exposeProxy = true)// 方案3：拆分到不同Service（最优雅）@Servicepublic class TransferService &#123; @Autowired private AccountService accountService; @Transactional public void doTransfer(Long fromId, Long toId, BigDecimal amount) &#123; accountService.deduct(fromId, amount); accountService.add(toId, amount); &#125;&#125;
场景二：方法非public失效代码@Servicepublic class OrderService &#123; @Transactional void createOrder(Order order) &#123; // 默认包级访问，事务失效！ orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); &#125; @Transactional private void processOrder(Order order) &#123; // private方法，事务失效！ orderMapper.update(order); &#125; @Transactional protected void cancelOrder(Long orderId) &#123; // protected方法，事务失效！ orderMapper.delete(orderId); &#125;&#125;
原因分析// Spring AOP创建代理时，会检查方法修饰符// TransactionAttributeSourcePointcut.matches() 中：public boolean matches(Method method, Class&lt;?&gt; targetClass) &#123; // 直接判断方法是否为public if (!Modifier.isPublic(method.getModifiers())) &#123; return false; // 非public方法直接不匹配，不创建事务增强 &#125; // ...&#125;
解决方案@Servicepublic class OrderService &#123; @Transactional public void createOrder(Order order) &#123; // 必须是public orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); &#125;&#125;
场景三：异常被catch吞掉失效代码@Servicepublic class OrderService &#123; @Transactional public void createOrder(Order order) &#123; try &#123; orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); // 即使这里抛异常，也被catch了 int i = 1 / 0; &#125; catch (Exception e) &#123; log.error(&quot;创建订单失败&quot;, e); // 异常被吞掉，事务不会回滚！ &#125; &#125;&#125;
原因分析// Spring事务回滚的触发条件：方法抛出异常，代理对象捕获到异常后回滚// TransactionInterceptor.invokeWithinTransaction()：try &#123; result = invocation.proceed(); // 执行目标方法&#125; catch (Throwable ex) &#123; completeTransactionAfterThrowing(txInfo, ex); // 捕获异常，回滚事务 throw ex; // 重新抛出&#125;// 如果异常在方法内部被catch，代理对象捕获不到异常，自然不会回滚
解决方案// 方案1：catch后重新抛出@Transactionalpublic void createOrder(Order order) &#123; try &#123; orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); &#125; catch (Exception e) &#123; log.error(&quot;创建订单失败&quot;, e); throw new BusinessException(&quot;创建订单失败&quot;); // 重新抛出 &#125;&#125;// 方案2：手动标记回滚@Transactionalpublic void createOrder(Order order) &#123; try &#123; orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); &#125; catch (Exception e) &#123; log.error(&quot;创建订单失败&quot;, e); TransactionAspectSupport.currentTransactionStatus().setRollbackOnly(); &#125;&#125;
场景四：rollbackFor配置错误失效代码@Servicepublic class OrderService &#123; @Transactional // 默认只回滚RuntimeException和Error public void createOrder(Order order) throws BusinessException &#123; orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); // BusinessException如果是checked exception，不会回滚！ throw new BusinessException(&quot;库存不足&quot;); &#125; @Transactional(rollbackFor = BusinessException.class) // 正确 public void createOrderV2(Order order) throws BusinessException &#123; orderMapper.insert(order); orderItemMapper.batchInsert(order.getItems()); throw new BusinessException(&quot;库存不足&quot;); // 会回滚 &#125;&#125;
原因分析// Spring默认回滚策略：// RuleBasedTransactionAttribute：public boolean rollbackOn(Throwable ex) &#123; // 默认只回滚RuntimeException和Error // 不回滚checked exception（即Exception的子类但非RuntimeException） if (ex instanceof RuntimeException || ex instanceof Error) &#123; return true; &#125; return false;&#125;// 自定义BusinessException如果继承Exception而非RuntimeException// 则默认不会触发回滚
最佳实践// 推荐：统一指定rollbackFor = Exception.class@Transactional(rollbackFor = Exception.class)public void createOrder(Order order) &#123; // 所有异常都回滚，避免遗漏&#125;
场景五：数据库引擎不支持事务失效代码-- MySQL建表时使用了MyISAM引擎CREATE TABLE `order` ( `id` bigint NOT NULL AUTO_INCREMENT, `order_no` varchar(32) NOT NULL, PRIMARY KEY (`id`)) ENGINE=MyISAM; -- MyISAM不支持事务！
原因分析MySQL存储引擎对比：- InnoDB：支持事务、行锁、外键（推荐）- MyISAM：不支持事务、表锁、全文索引（已淘汰）即使代码层面加了@Transactional，底层数据库不支持事务，Spring也无法强制让数据库回滚。
解决方案-- 建表时统一使用InnoDB引擎CREATE TABLE `order` ( `id` bigint NOT NULL AUTO_INCREMENT, `order_no` varchar(32) NOT NULL, PRIMARY KEY (`id`)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4;-- 修改已有表的引擎ALTER TABLE `order` ENGINE=InnoDB;
场景六：未被Spring管理失效代码// 没有加@Service注解，不是Spring Beanpublic class OrderService &#123; @Transactional // 事务失效！Spring根本不知道这个类的存在 public void createOrder(Order order) &#123; orderMapper.insert(order); &#125;&#125;
解决方案@Service // 必须交由Spring管理public class OrderService &#123; @Transactional public void createOrder(Order order) &#123; orderMapper.insert(order); &#125;&#125;
场景七：传播行为配置不当失效代码@Servicepublic class OrderService &#123; @Autowired private LogService logService; @Transactional public void createOrder(Order order) &#123; orderMapper.insert(order); // 日志方法用了NOT_SUPPORTED，会挂起当前事务 // 如果日志写入失败，订单不会回滚 logService.saveLog(&quot;创建订单&quot;); &#125;&#125;@Servicepublic class LogService &#123; @Transactional(propagation = Propagation.NOT_SUPPORTED) public void saveLog(String message) &#123; logMapper.insert(message); &#125;&#125;
传播行为速查表REQUIRED（默认）：有事务加入，无事务新建SUPPORTS：有事务加入，无事务非事务执行MANDATORY：必须在事务中，否则抛异常REQUIRES_NEW：始终新建事务，挂起当前事务NOT_SUPPORTED：非事务执行，挂起当前事务NEVER：非事务执行，存在事务则抛异常NESTED：有事务则嵌套执行，无事务新建
场景八：多线程场景失效代码@Servicepublic class OrderService &#123; @Transactional public void batchCreateOrder(List&lt;Order&gt; orders) &#123; // 多线程执行，每个线程获取不同的数据库连接 // Spring事务绑定在ThreadLocal中，子线程无法获取父线程事务 orders.parallelStream().forEach(order -&gt; &#123; orderMapper.insert(order); // 不在同一个事务中！ &#125;); &#125;&#125;
原因分析// Spring事务通过ThreadLocal存储数据库连接// TransactionSynchronizationManager：private static final ThreadLocal&lt;Map&lt;Object, Object&gt;&gt; resources = new NamedThreadLocal&lt;&gt;(&quot;Transactional resources&quot;);// 多线程场景下，每个线程有自己的ThreadLocal// 子线程无法获取父线程的数据库连接，自然不在同一事务中
解决方案// 方案1：主线程统一提交@Transactionalpublic void batchCreateOrder(List&lt;Order&gt; orders) &#123; // 在主线程中顺序执行，保证同一事务 for (Order order : orders) &#123; orderMapper.insert(order); &#125;&#125;// 方案2：编程式事务public void batchCreateOrder(List&lt;Order&gt; orders) &#123; List&lt;CompletableFuture&lt;Void&gt;&gt; futures = orders.stream() .map(order -&gt; CompletableFuture.runAsync(() -&gt; &#123; transactionTemplate.execute(status -&gt; &#123; orderMapper.insert(order); return null; &#125;); &#125;, threadPool)) .collect(Collectors.toList()); CompletableFuture.allOf(futures.toArray(new CompletableFuture[0])).join();&#125;
事务失效场景速查表
序号 失效场景 根本原因 解决方案
1 同类方法调用 绕过代理对象 注入自身&#x2F;拆分Service
2 方法非public AOP不拦截非public 改为public
3 异常被catch 代理捕获不到异常 重新抛出&#x2F;手动回滚
4 rollbackFor错误 默认不回滚checked 指定rollbackFor
5 引擎不支持 MyISAM无事务 使用InnoDB
6 未被Spring管理 不是Spring Bean 加@Service
7 传播行为不当 NOT_SUPPORTED等 选择合适的传播行为
8 多线程场景 ThreadLocal隔离 主线程统一&#x2F;编程式事务
总结Spring事务失效的本质就一句话：代理对象没有被正确调用。无论是同类调用绕过代理、非public方法不被代理、异常被吞掉代理无法感知，还是多线程ThreadLocal隔离，归根结底都是代理机制被破坏。 记住一个原则：想让事务生效，必须让代理对象来管理你的方法调用。遇到事务问题，先画调用链路，看是否经过了代理对象，80%的问题都能快速定位。

前言日常开发中，@Autowired和@Resource用得最多，但一直没搞清楚它们的区别。直到一次线上问题：同一个接口两个实现类，@Autowired报错但@Resource正常。这次排查让我深入研究了两种注入方式的底层实现。
@Autowired vs @Resource 速览


