name属性


@Autowired注入原理注入入口// AutowiredAnnotationBeanPostProcessor// 负责处理@Autowired和@Value注解// 1. 在Bean创建后，属性填充阶段触发// 2. 通过MergedBeanDefinitionPostProcessor收集注入元数据// 3. 通过InstantiationAwareBeanPostProcessor完成注入@Overridepublic void postProcessMergedBeanDefinition(RootBeanDefinition beanDefinition,        Class&lt;?&gt; beanType, String beanName) &#123;    // 扫描@Autowired和@Value注解，构建InjectionMetadata    InjectionMetadata metadata = findAutowiringMetadata(beanName, beanType, null);    metadata.checkConfigMembers(beanDefinition);&#125;@Overridepublic PropertyValues postProcessProperties(PropertyValues pvs, Object bean, String beanName) &#123;    InjectionMetadata metadata = findAutowiringMetadata(beanName, bean.getClass(), pvs);    try &#123;        metadata.inject(bean, beanName, pvs);  // 执行注入    &#125; catch (BeanCreationException ex) &#123;        throw ex;    &#125;    return pvs;&#125;

查找注入点的过程// findAutowiringMetadata → buildAutowiringMetadataprivate InjectionMetadata buildAutowiringMetadata(Class&lt;?&gt; clazz) &#123;    List&lt;InjectionMetadata.InjectedElement&gt; elements = new ArrayList&lt;&gt;();    Class&lt;?&gt; targetClass = clazz;    do &#123;        List&lt;InjectionMetadata.InjectedElement&gt; currElements = new ArrayList&lt;&gt;();        // 1. 扫描字段上的@Autowired        ReflectionUtils.doWithLocalFields(targetClass, field -&gt; &#123;            AnnotationAttributes ann = findAutowiredAnnotation(field);            if (ann != null) &#123;                if (Modifier.isStatic(field.getModifiers())) &#123;                    return;  // @Autowired不支持static字段                &#125;                boolean required = determineRequiredStatus(ann);                currElements.add(new AutowiredFieldElement(field, required));            &#125;        &#125;);        // 2. 扫描方法上的@Autowired        ReflectionUtils.doWithLocalMethods(targetClass, method -&gt; &#123;            AnnotationAttributes ann = findAutowiredAnnotation(method);            if (ann != null) &#123;                if (Modifier.isStatic(method.getModifiers())) &#123;                    return;                &#125;                boolean required = determineRequiredStatus(ann);                currElements.add(new AutowiredMethodElement(method, required));            &#125;        &#125;);        elements.addAll(0, currElements);        targetClass = targetClass.getSuperclass();    &#125; while (targetClass != null &amp;&amp; targetClass != Object.class);    return new InjectionMetadata(clazz, elements);&#125;

按类型查找的核心：resolveDependency// DefaultListableBeanFactory.resolveDependency()public Object resolveDependency(DependencyDescriptor descriptor, String requestingBeanName,        Set&lt;String&gt; autowiredBeanNames, TypeConverter typeConverter) &#123;    // 1. 处理@Value    if (descriptor.hasAnnotation(Value.class)) &#123;        return resolveEmbeddedValue(descriptor);    &#125;    // 2. 处理Optional和ObjectProvider    if (Optional.class == descriptor.getDependencyType()) &#123;        return createOptionalDependency(descriptor, requestingBeanName);    &#125;    if (ObjectProvider.class == descriptor.getDependencyType()) &#123;        return new DependencyObjectProvider(descriptor, requestingBeanName);    &#125;    // 3. 按类型查找    Object result = doResolveDependency(descriptor, requestingBeanName, autowiredBeanNames, typeConverter);    return result;&#125;// doResolveDependency核心逻辑public Object doResolveDependency(DependencyDescriptor descriptor, String requestingBeanName,        Set&lt;String&gt; autowiredBeanNames, TypeConverter typeConverter) &#123;    // 1. 按类型查找所有候选Bean    Map&lt;String, Object&gt; matchingBeans = findAutowireCandidates(beanName, type, descriptor);    if (matchingBeans.isEmpty()) &#123;        // 没找到候选Bean        if (isRequired(descriptor)) &#123;            raiseNoMatchingBeanFound(type, requestingBeanName);  // 抛异常        &#125;        return null;    &#125;    // 2. 只有一个候选 → 直接注入    if (matchingBeans.size() == 1) &#123;        return matchingBeans.values().iterator().next();    &#125;    // 3. 多个候选 → 需要进一步筛选    // 3.1 @Qualifier筛选    // 3.2 按字段名/参数名匹配    // 3.3 @Primary标注的Bean优先    // 3.4 Priority最高的Bean优先    return determineAutowireCandidate(matchingBeans, descriptor);&#125;

多个候选Bean的筛选策略// determineAutowireCandidateprotected String determineAutowireCandidate(Map&lt;String, Object&gt; candidates,        DependencyDescriptor descriptor) &#123;    // 1. @Primary优先    for (Map.Entry&lt;String, Object&gt; entry : candidates.entrySet()) &#123;        if (isPrimary(entry.getKey(), entry.getValue())) &#123;            return entry.getKey();        &#125;    &#125;    // 2. @Priority优先（值越小优先级越高）    Object priority = null;    String priorityBeanName = null;    for (Map.Entry&lt;String, Object&gt; entry : candidates.entrySet()) &#123;        Integer priorityValue = getPriority(entry.getValue());        if (priorityValue != null) &#123;            if (priority == null || priorityValue &lt; (Integer) priority) &#123;                priority = priorityValue;                priorityBeanName = entry.getKey();            &#125;        &#125;    &#125;    if (priorityBeanName != null) return priorityBeanName;    // 3. 按名称匹配（字段名或参数名）    for (Map.Entry&lt;String, Object&gt; entry : candidates.entrySet()) &#123;        if (descriptor.getDependencyName().equals(entry.getKey())) &#123;            return entry.getKey();  // 名称匹配        &#125;    &#125;    return null;  // 无法确定，抛出NoUniqueBeanDefinitionException&#125;

@Resource注入原理// CommonAnnotationBeanPostProcessor处理@Resource// 它是JSR-250规范的实现，同时处理@PostConstruct和@PreDestroy// 1. 收集@Resource注入点private InjectionMetadata buildResourceMetadata(Class&lt;?&gt; clazz) &#123;    List&lt;InjectionMetadata.InjectedElement&gt; elements = new ArrayList&lt;&gt;();    ReflectionUtils.doWithLocalFields(targetClass, field -&gt; &#123;        if (field.isAnnotationPresent(Resource.class)) &#123;            // @Resource只支持字段和方法注入，不支持构造器            Resource resource = field.getAnnotation(Resource.class);            String resourceName = resource.name();  // 获取name属性            elements.add(new ResourceElement(field, resourceName, resource));        &#125;    &#125;);    return new InjectionMetadata(clazz, elements);&#125;// 2. @Resource的查找逻辑// 先按名称查找，再按类型查找protected Object getResourceToInject(Object target, String requestingBeanName) &#123;    return autowireResource(this.resourceFactory, element, requestingBeanName);&#125;protected Object autowireResource(BeanFactory factory, ResourceElement element,         String requestingBeanName) &#123;    String name = element.name;    Class&lt;?&gt; type = element.type;    // 1. 如果指定了name，按名称查找    if (name != null &amp;&amp; !name.isEmpty()) &#123;        return factory.getBean(name, type);    &#125;    // 2. 未指定name，先按字段名查找    try &#123;        return factory.getBean(element.fieldName, type);    &#125; catch (NoSuchBeanDefinitionException e) &#123;        // 3. 按名称找不到，按类型查找        return factory.getBean(type);    &#125;&#125;

同一接口多个实现的注入场景：多个实现类public interface PayService &#123;    void pay(String orderId, BigDecimal amount);&#125;@Service(&quot;aliPayService&quot;)public class AliPayServiceImpl implements PayService &#123;    @Override    public void pay(String orderId, BigDecimal amount) &#123;        System.out.println(&quot;支付宝支付&quot;);    &#125;&#125;@Service(&quot;wechatPayService&quot;)public class WechatPayServiceImpl implements PayService &#123;    @Override    public void pay(String orderId, BigDecimal amount) &#123;        System.out.println(&quot;微信支付&quot;);    &#125;&#125;

方式1：@Autowired + @Qualifier@Servicepublic class OrderService &#123;    @Autowired    @Qualifier(&quot;aliPayService&quot;)  // 按名称指定    private PayService payService;&#125;

方式2：@Resource(name)@Servicepublic class OrderService &#123;    @Resource(name = &quot;aliPayService&quot;)  // 直接指定名称    private PayService payService;&#125;

方式3：字段名匹配@Servicepublic class OrderService &#123;    @Autowired    private PayService aliPayService;  // 字段名=Bean名，自动匹配    @Resource    private PayService wechatPayService;  // @Resource也支持字段名匹配&#125;

方式4：@Primary@Service@Primary  // 标记为默认注入的实现public class AliPayServiceImpl implements PayService &#123;&#125;@Servicepublic class OrderService &#123;    @Autowired  // 不需要@Qualifier，自动注入@Primary的实现    private PayService payService;&#125;

方式5：Map&#x2F;List集合注入@Servicepublic class PayServiceFactory &#123;    // 注入所有PayService实现，key=Bean名    @Autowired    private Map&lt;String, PayService&gt; payServiceMap;    // 注入所有PayService实现，List形式    @Autowired    private List&lt;PayService&gt; payServiceList;    public PayService getPayService(String type) &#123;        return payServiceMap.get(type + &quot;PayService&quot;);    &#125;&#125;

构造器注入 vs 字段注入 vs Setter注入三种注入方式@Servicepublic class OrderService &#123;    // 1. 字段注入（最常见但不推荐）    @Autowired    private UserService userService;    // 2. 构造器注入（推荐）    private final UserService userService;    private final OrderMapper orderMapper;    @Autowired  // Spring 4.3+ 单构造器可省略    public OrderService(UserService userService, OrderMapper orderMapper) &#123;        this.userService = userService;        this.orderMapper = orderMapper;    &#125;    // 3. Setter注入（可选依赖）    private NotificationService notificationService;    @Autowired(required = false)  // 可选注入    public void setNotificationService(NotificationService notificationService) &#123;        this.notificationService = notificationService;    &#125;&#125;

为什么推荐构造器注入1. 不可变性：字段可以是final，确保依赖不变2. 完整性：构造时所有依赖都已注入，不会出现NPE3. 显式依赖：所有必需依赖在构造函数参数中一目了然4. 便于测试：不需要反射就能注入mock对象5. 避免循环依赖：Spring能更好地检测循环依赖

// 构造器注入 + Lombok简化@Service@RequiredArgsConstructor  // 生成final字段的构造器public class OrderService &#123;    private final UserService userService;     // final → 构造器注入    private final OrderMapper orderMapper;     // final → 构造器注入    // 非必需依赖    @Autowired(required = false)    private NotificationService notificationService;&#125;

循环依赖与注入方式// 字段注入的循环依赖：Spring通过三级缓存可以解决@Servicepublic class A &#123;    @Autowired    private B b;&#125;@Servicepublic class B &#123;    @Autowired    private A a;&#125;// 构造器注入的循环依赖：无法解决！@Servicepublic class A &#123;    private final B b;    public A(B b) &#123; this.b = b; &#125;  // 构造A需要B，构造B需要A → 死锁&#125;@Servicepublic class B &#123;    private final A a;    public B(A a) &#123; this.a = a; &#125;&#125;// 解决：@Lazy@Servicepublic class A &#123;    private final B b;    public A(@Lazy B b) &#123; this.b = b; &#125;  // 注入B的代理对象&#125;

线上问题：@Autowired注入null场景1：在构造函数中使用依赖@Servicepublic class UserService &#123;    @Autowired    private UserMapper userMapper;    private List&lt;String&gt; cachedUsers;    // ❌ 构造函数执行时，@Autowired还未注入    public UserService() &#123;        this.cachedUsers = userMapper.selectAll();  // NPE！    &#125;&#125;// ✅ 使用@PostConstruct@Servicepublic class UserService &#123;    @Autowired    private UserMapper userMapper;    private List&lt;String&gt; cachedUsers;    @PostConstruct    public void init() &#123;        this.cachedUsers = userMapper.selectAll();  // 依赖注入完成后执行    &#125;&#125;

场景2：在非Spring管理的对象中使用@Autowired// ❌ 自己new的对象，Spring不会管理public class UserHelper &#123;    @Autowired    private UserMapper userMapper;  // 永远是null&#125;UserHelper helper = new UserHelper();  // Spring不管理// ✅ 交给Spring管理@Componentpublic class UserHelper &#123;    @Autowired    private UserMapper userMapper;&#125;

场景3：在静态方法中使用依赖@Servicepublic class SpringContextHolder implements ApplicationContextAware &#123;    private static ApplicationContext context;    @Override    public void setApplicationContext(ApplicationContext ctx) &#123;        context = ctx;    &#125;    // 在非Spring管理类中获取Bean    public static &lt;T&gt; T getBean(Class&lt;T&gt; clazz) &#123;        return context.getBean(clazz);    &#125;&#125;

面试高频问题1. @Autowired和@Resource的区别？@Autowired是Spring注解，先按类型再按名称；@Resource是Java标准注解，先按名称再按类型。推荐使用构造器注入。
2. @Autowired如何处理多个实现类？@Qualifier指定名称、@Primary标记默认、字段名匹配、Map&#x2F;List集合注入。
3. 为什么推荐构造器注入？不可变性、完整性、显式依赖、便于测试、避免循环依赖。
最佳实践
推荐构造器注入：final字段 + @RequiredArgsConstructor
可选依赖用Setter：@Autowired(required &#x3D; false)
避免字段注入：虽然简洁但不利于测试和维护
多实现用@Qualifier：明确指定，避免歧义
理解注入时机：构造函数→字段注入→@PostConstruct

总结依赖注入是Spring的核心机制。2023年深入源码后，核心认知是：@Autowired按类型优先，@Resource按名称优先，构造器注入是最安全的方式。理解了注入原理和时机，就不会再遇到”注入为null”的诡异问题。

前言用了两年@Transactional，只知道加在方法上就能回滚，直到线上出现数据不一致——明明加了事务注解，部分数据却没回滚。排查后发现是事务失效导致的。这次事故让我下定决心搞透Spring事务的底层实现。 Spring事务架构核心组件@Transactional ↓Spring AOP代理 ↓TransactionInterceptor（事务拦截器） ↓PlatformTransactionManager（事务管理器） ↓DataSource → Connection → 数据库事务
三大核心接口// 1. PlatformTransactionManager：事务管理器（策略模式）public interface PlatformTransactionManager &#123; TransactionStatus getTransaction(TransactionDefinition definition); // 获取事务 void commit(TransactionStatus status); // 提交 void rollback(TransactionStatus status); // 回滚&#125;// 2. TransactionDefinition：事务定义（传播行为、隔离级别等）public interface TransactionDefinition &#123; int getPropagationBehavior(); // 传播行为 int getIsolationLevel(); // 隔离级别 int getTimeout(); // 超时时间 boolean isReadOnly(); // 是否只读&#125;// 3. TransactionStatus：事务运行状态public interface TransactionStatus &#123; boolean isNewTransaction(); // 是否新事务 boolean hasSavepoint(); // 是否有保存点 void setRollbackOnly(); // 标记回滚 boolean isRollbackOnly(); // 是否已标记回滚&#125;
事务拦截器源码分析调用入口// TransactionInterceptor.invoke()public Object invoke(MethodInvocation invocation) throws Throwable &#123; Class&lt;?&gt; targetClass = invocation.getThis().getClass(); return invokeWithinTransaction(invocation.getMethod(), targetClass, invocation::proceed);&#125;protected Object invokeWithinTransaction(Method method, Class&lt;?&gt; targetClass, InvocationCallback invocation) &#123; // 1. 获取事务属性 TransactionAttributeSource tas = getTransactionAttributeSource(); TransactionAttribute txAttr = tas.getTransactionAttribute(method, targetClass); // 2. 获取事务管理器 PlatformTransactionManager tm = determineTransactionManager(txAttr); // 3. 获取事务（核心） TransactionStatus status = tm.getTransaction(txAttr); Object retVal; try &#123; // 4. 执行业务方法 retVal = invocation.proceedWithInvocation(); &#125; catch (Throwable ex) &#123; // 5. 异常处理：根据规则决定回滚还是提交 completeTransactionAfterThrowing(txInfo, ex); throw ex; &#125; // 6. 提交事务 commitTransactionAfterReturning(txInfo); return retVal;&#125;
getTransaction核心流程// AbstractPlatformTransactionManager.getTransaction()public final TransactionStatus getTransaction(TransactionDefinition definition) &#123; // 1. 获取当前事务对象（DataSource级别） Object transaction = doGetTransaction(); // 2. 判断当前是否存在事务 if (isExistingTransaction(transaction)) &#123; // 存在事务 → 根据传播行为处理 return handleExistingTransaction(definition, transaction); &#125; // 3. 不存在事务 // 检查传播行为 if (definition.getPropagationBehavior() == PROPAGATION_MANDATORY) &#123; throw new IllegalTransactionStateException(&quot;当前不存在事务，但传播行为为MANDATORY&quot;); &#125; if (definition.getPropagationBehavior() == PROPAGATION_REQUIRED || definition.getPropagationBehavior() == PROPAGATION_REQUIRES_NEW || definition.getPropagationBehavior() == PROPAGATION_NESTED) &#123; // 挂起空事务，创建新事务 SuspendedResourcesHolder suspendedResources = suspend(null); try &#123; // 开启新事务 return startTransaction(definition, transaction, false, suspendedResources); &#125; catch (RuntimeException ex) &#123; resume(null, suspendedResources); throw ex; &#125; &#125; // 其他传播行为（SUPPORTS、NOT_SUPPORTED、NEVER）→ 不创建事务 return prepareTransactionStatus(definition, null, true, false, true, null);&#125;
startTransactionprivate TransactionStatus startTransaction(TransactionDefinition definition, Object transaction, boolean newSynchronization, SuspendedResourcesHolder suspendedResources) &#123; // 1. 是否开启新同步 boolean newSynchronization = getTransactionSynchronization() != SYNCHRONIZATION_NEVER; // 2. 核心操作：获取Connection，设置autoCommit=false doBegin(transaction, definition); // 3. 准备TransactionStatus return prepareTransactionStatus(definition, transaction, true, newSynchronization, debugEnabled, suspendedResources);&#125;
doBegin——真正开启事务// DataSourceTransactionManager.doBegin()protected void doBegin(Object transaction, TransactionDefinition definition) &#123; DataSourceTransactionObject txObject = (DataSourceTransactionObject) transaction; Connection con = null; try &#123; // 1. 获取数据库连接 if (!txObject.hasConnectionHolder() || txObject.getConnectionHolder().isSynchronizedWithTransaction()) &#123; Connection newCon = obtainDataSource().getConnection(); txObject.setConnectionHolder(new ConnectionHolder(newCon), true); &#125; // 2. 关键：设置手动提交 con = txObject.getConnectionHolder().getConnection(); Integer previousIsolationLevel = DataSourceUtils.prepareConnectionForTransaction(con, definition); txObject.setPreviousIsolationLevel(previousIsolationLevel); // 核心操作：关闭自动提交 if (con.getAutoCommit()) &#123; txObject.setMustRestoreAutoCommit(true); con.setAutoCommit(false); // ← 这就是Spring事务的底层实现 &#125; // 3. 设置超时 if (definition.getTimeout() != TransactionDefinition.TIMEOUT_DEFAULT) &#123; txObject.getConnectionHolder().setTimeoutInSeconds(definition.getTimeout()); &#125; // 4. 绑定到当前线程 if (txObject.isNewConnectionHolder()) &#123; TransactionSynchronizationManager.bindResource( obtainDataSource(), txObject.getConnectionHolder()); &#125; &#125; catch (Throwable ex) &#123; releaseConnection(con); throw new CannotCreateTransactionException(&quot;Could not open JDBC Connection for transaction&quot;, ex); &#125;&#125;
核心发现：Spring事务的本质就是connection.setAutoCommit(false)，然后通过ThreadLocal将Connection绑定到当前线程。 事务传播行为源码分析REQUIRED（默认）// 如果当前没有事务，就新建一个；如果有，就加入当前事务@Transactional(propagation = Propagation.REQUIRED)public void methodA() &#123; userMapper.insert(user); orderService.methodB(); // B加入A的事务&#125;@Transactional(propagation = Propagation.REQUIRED)public void methodB() &#123; orderMapper.insert(order);&#125;// A和B在同一个事务中，任一异常全部回滚
REQUIRES_NEW// 总是新建事务，挂起当前事务@Transactional(propagation = Propagation.REQUIRED)public void methodA() &#123; userMapper.insert(user); try &#123; logService.methodB(); // B在新事务中执行 &#125; catch (Exception e) &#123; // B回滚不影响A &#125;&#125;@Transactional(propagation = Propagation.REQUIRES_NEW)public void methodB() &#123; logMapper.insert(log);&#125;// B在新事务中执行，B回滚不影响A，A回滚也不影响B（已提交）
源码层面：handleExistingTransaction中，遇到REQUIRES_NEW会先suspend当前事务（解绑Connection），然后startTransaction创建新事务，执行完后resume恢复原事务。 NESTED// 在当前事务中创建保存点（Savepoint）@Transactional(propagation = Propagation.REQUIRED)public void methodA() &#123; userMapper.insert(user); try &#123; orderService.methodB(); // B在嵌套事务中执行 &#125; catch (Exception e) &#123; // B回滚到Savepoint，A继续执行 &#125;&#125;@Transactional(propagation = Propagation.NESTED)public void methodB() &#123; orderMapper.insert(order); if (true) throw new RuntimeException(&quot;B失败&quot;);&#125;// B回滚到保存点，A不受影响；但A回滚时B也会回滚
传播行为对比
传播行为 当前无事务 当前有事务 典型场景
REQUIRED 新建事务 加入当前事务 默认选择
REQUIRES_NEW 新建事务 挂起当前，新建事务 日志记录
NESTED 新建事务 嵌套事务(Savepoint) 子操作允许失败
SUPPORTS 非事务执行 加入当前事务 查询方法
NOT_SUPPORTED 非事务执行 挂起当前事务 不需要事务的操作
MANDATORY 抛异常 加入当前事务 强制要求事务
NEVER 非事务执行 抛异常 强制不要事务
事务失效的所有场景1. 同类方法调用（最常见）@Servicepublic class UserService &#123; public void methodA() &#123; this.methodB(); // ❌ 事务失效 &#125; @Transactional public void methodB() &#123;&#125;&#125;// 原因：this是目标对象，不是代理对象，不经过TransactionInterceptor
2. 非public方法@Servicepublic class UserService &#123; @Transactional void method() &#123;&#125; // ❌ 默认只代理public方法 @Transactional protected void method2() &#123;&#125; // ❌ 同上&#125;
3. 异常类型不匹配@Servicepublic class UserService &#123; @Transactional // 默认只回滚RuntimeException和Error public void save() throws IOException &#123; userMapper.insert(user); throw new IOException(&quot;文件异常&quot;); // ❌ 不回滚 &#125;&#125;// ✅ 指定回滚异常@Transactional(rollbackFor = Exception.class)public void save() throws IOException &#123; throw new IOException(&quot;文件异常&quot;); // 回滚&#125;
4. 异常被catch吞掉@Transactionalpublic void save() &#123; try &#123; userMapper.insert(user); int i = 1 / 0; &#125; catch (Exception e) &#123; log.error(&quot;异常&quot;, e); // ❌ 异常被吞，事务提交 &#125;&#125;
5. 数据库引擎不支持-- MyISAM不支持事务，必须用InnoDBSHOW TABLE STATUS LIKE &#x27;user&#x27;;-- 如果Engine=MyISAM → 事务不生效ALTER TABLE user ENGINE=InnoDB;
6. 传播行为设置错误@Transactional(propagation = Propagation.NOT_SUPPORTED)public void save() &#123; // 以非事务方式执行，异常不回滚&#125;@Transactional(propagation = Propagation.NEVER)public void save() &#123; // 如果当前有事务，直接抛异常&#125;
7. 未被Spring管理// ❌ 没有交给Spring容器public class UserService &#123; @Transactional public void save() &#123;&#125;&#125;
线上问题排查实战问题：事务部分回滚@Servicepublic class OrderService &#123; @Autowired private UserService userService; @Autowired private LogService logService; @Transactional public void createOrder(OrderDTO dto) &#123; // 1. 创建订单 orderMapper.insert(order); // 2. 扣减库存 stockService.deduct(dto.getSkuId(), dto.getQuantity()); // 3. 记录日志（不想被回滚影响） logService.recordLog(log); // 如果这里异常，订单也回滚 &#125;&#125;// 解决：日志操作用REQUIRES_NEW@Servicepublic class LogService &#123; @Transactional(propagation = Propagation.REQUIRES_NEW) public void recordLog(Log log) &#123; logMapper.insert(log); &#125;&#125;
问题：多线程事务失效@Servicepublic class BatchService &#123; @Transactional public void batchInsert(List&lt;User&gt; users) &#123; // ❌ 多线程中@Transactional不生效 // 每个线程获取的是不同的Connection users.parallelStream().forEach(user -&gt; &#123; userMapper.insert(user); // 不在事务中 &#125;); &#125;&#125;// 正确做法：主线程控制事务，子线程只做计算@Transactionalpublic void batchInsert(List&lt;User&gt; users) &#123; // 分批插入，每批500条 List&lt;List&lt;User&gt;&gt; batches = Lists.partition(users, 500); for (List&lt;User&gt; batch : batches) &#123; userMapper.batchInsert(batch); // 在主线程事务中 &#125;&#125;
实战：编程式事务// 有时候声明式事务不够灵活，需要编程式事务@Service@RequiredArgsConstructorpublic class OrderService &#123; private final TransactionTemplate transactionTemplate; private final PlatformTransactionManager transactionManager; // 方式1：TransactionTemplate（推荐） public void createOrder(OrderDTO dto) &#123; transactionTemplate.execute(status -&gt; &#123; try &#123; orderMapper.insert(order); stockService.deduct(dto.getSkuId(), dto.getQuantity()); return true; &#125; catch (Exception e) &#123; status.setRollbackOnly(); return false; &#125; &#125;); &#125; // 方式2：PlatformTransactionManager public void createOrder2(OrderDTO dto) &#123; DefaultTransactionDefinition def = new DefaultTransactionDefinition(); def.setPropagationBehavior(TransactionDefinition.PROPAGATION_REQUIRED); TransactionStatus status = transactionManager.getTransaction(def); try &#123; orderMapper.insert(order); stockService.deduct(dto.getSkuId(), dto.getQuantity()); transactionManager.commit(status); &#125; catch (Exception e) &#123; transactionManager.rollback(status); &#125; &#125;&#125;
面试高频问题1. Spring事务的本质？connection.setAutoCommit(false) + ThreadLocal绑定Connection到当前线程。 2. REQUIRED和REQUIRES_NEW的区别？REQUIRED加入当前事务，一荣俱荣一损俱损；REQUIRES_NEW新建独立事务，互不影响。 3. NESTED和REQUIRES_NEW的区别？NESTED是外层事务的子事务（Savepoint），外层回滚子事务也回滚；REQUIRES_NEW是完全独立的新事务，互不影响。 4. @Transactional(readOnly&#x3D;true)的作用？ 数据库层面：InnoDB不做change buffer，查询性能提升 Spring层面：标记只读，部分事务管理器可以做优化 注意：readOnly只对事务内的查询有效
最佳实践 永远指定rollbackFor &#x3D; Exception.class：避免checked异常不回滚 事务方法必须是public：private&#x2F;protected事务不生效 避免同类调用：用AopContext或注入自身 事务粒度要小：只包裹必要的数据库操作，不要包含RPC调用 只读查询加readOnly：性能优化 日志操作用REQUIRES_NEW：避免日志回滚丢失
总结Spring事务的本质是AOP + Connection.setAutoCommit(false) + ThreadLocal。2023年深入源码后，我彻底理解了事务传播行为的实现机制，也掌握了事务失效的所有场景。线上遇到数据不一致问题，不再盲目排查，而是从代理是否生效、异常是否被吞、传播行为是否正确三个维度系统分析。

前言多线程开发中，锁是最基本的同步工具。早期只知道synchronized，后来发现还有ReentrantLock、ReadWriteLock。到底该用哪个？它们的底层实现有什么区别？2023年系统学习后终于搞清楚了。 Synchronized——JVM内置锁基本用法// 1. 修饰实例方法：锁当前对象public synchronized void method() &#123; // 同一实例的该方法同一时刻只能一个线程执行&#125;// 2. 修饰静态方法：锁Class对象public static synchronized void method() &#123; // 该类的所有实例同一时刻只能一个线程执行&#125;// 3. 修饰代码块：锁指定对象public void method() &#123; synchronized(this) &#123; // 锁当前对象 // ... &#125; synchronized(User.class) &#123; // 锁Class对象 // ... &#125; synchronized(lock) &#123; // 锁指定对象 // ... &#125;&#125;
底层实现synchronized基于Monitor（管程）实现：1. 代码块：monitorenter / monitorexit 字节码指令2. 方法：ACC_SYNCHRONIZED 标志位Monitor的本质：- 每个对象关联一个Monitor- Monitor有EntryList（阻塞队列）和WaitSet（等待队列）- 线程通过CAS竞争Monitor的Owner
锁升级过程无锁 → 偏向锁 → 轻量级锁 → 重量级锁偏向锁：只有一个线程访问，CAS记录线程ID，后续无需同步轻量级锁：两个线程交替访问，CAS自旋竞争重量级锁：竞争激烈，线程阻塞，涉及用户态/内核态切换注意：锁只能升级，不能降级（GC时可降级）
// 查看对象头中的锁信息&lt;dependency&gt; &lt;groupId&gt;org.openjdk.jol&lt;/groupId&gt; &lt;artifactId&gt;jol-core&lt;/artifactId&gt; &lt;version&gt;0.17&lt;/version&gt;&lt;/dependency&gt;Object obj = new Object();System.out.println(ClassLayout.parseInstance(obj).toPrintable());synchronized (obj) &#123; System.out.println(ClassLayout.parseInstance(obj).toPrintable()); // 锁标志位变化：001(无锁) → 000(轻量级锁) → 010(重量级锁)&#125;
ReentrantLock——JUC显式锁基本用法private final ReentrantLock lock = new ReentrantLock();public void method() &#123; lock.lock(); try &#123; // 业务逻辑 &#125; finally &#123; lock.unlock(); // 必须在finally中释放锁 &#125;&#125;
底层实现// ReentrantLock基于AQS（AbstractQueuedSynchronizer）实现// AQS核心：// 1. state变量：0=未锁定，&gt;0=锁定（支持重入，每次+1）// 2. CLH双向队列：存放等待线程// 3. CAS操作：竞争state// 公平锁：先到先得ReentrantLock fairLock = new ReentrantLock(true);// 非公平锁（默认）：允许插队ReentrantLock unfairLock = new ReentrantLock(false);// 公平锁获取锁：protected final boolean tryAcquire(int acquires) &#123; // 先检查队列中是否有等待线程 if (hasQueuedPredecessors()) return false; // 没有等待线程才CAS竞争 return compareAndSetState(0, acquires);&#125;// 非公平锁获取锁：final boolean nonfairTryAcquire(int acquires) &#123; // 直接CAS竞争，不管队列 if (compareAndSetState(0, acquires)) return true; // 竞争失败才入队&#125;
可中断锁// Synchronized不可中断：等待锁的线程无法响应中断// ReentrantLock可中断：lockInterruptibly()Thread t = new Thread(() -&gt; &#123; try &#123; lock.lockInterruptibly(); // 可被中断的获取锁 try &#123; // 业务逻辑 &#125; finally &#123; lock.unlock(); &#125; &#125; catch (InterruptedException e) &#123; log.info(&quot;线程被中断，放弃获取锁&quot;); &#125;&#125;);t.start();t.interrupt(); // 中断等待锁的线程
超时获取锁// tryLock：尝试获取锁，超时返回falseif (lock.tryLock(3, TimeUnit.SECONDS)) &#123; try &#123; // 获取锁成功 &#125; finally &#123; lock.unlock(); &#125;&#125; else &#123; // 获取锁超时 log.warn(&quot;获取锁超时&quot;);&#125;
Condition条件变量// Synchronized只有一把锁一个等待队列（wait/notify）// ReentrantLock支持多个Condition（多个等待队列）private final ReentrantLock lock = new ReentrantLock();private final Condition notEmpty = lock.newCondition(); // 非空条件private final Condition notFull = lock.newCondition(); // 非满条件// 生产者public void put(T item) throws InterruptedException &#123; lock.lock(); try &#123; while (count == items.length) &#123; notFull.await(); // 队列满，等待非满条件 &#125; items[putIndex] = item; notEmpty.signal(); // 通知消费者 &#125; finally &#123; lock.unlock(); &#125;&#125;// 消费者public T take() throws InterruptedException &#123; lock.lock(); try &#123; while (count == 0) &#123; notEmpty.await(); // 队列空，等待非空条件 &#125; T item = items[takeIndex]; notFull.signal(); // 通知生产者 return item; &#125; finally &#123; lock.unlock(); &#125;&#125;
ReadWriteLock——读写锁// 读读共享，读写互斥，写写互斥// 适合读多写少的场景private final ReadWriteLock rwLock = new ReentrantReadWriteLock();private final Lock readLock = rwLock.readLock();private final Lock writeLock = rwLock.writeLock();private Map&lt;String, String&gt; cache = new HashMap&lt;&gt;();// 读操作public String get(String key) &#123; readLock.lock(); try &#123; return cache.get(key); &#125; finally &#123; readLock.unlock(); &#125;&#125;// 写操作public void put(String key, String value) &#123; writeLock.lock(); try &#123; cache.put(key, value); &#125; finally &#123; writeLock.unlock(); &#125;&#125;
读写锁的坑：写饥饿读多写少场景：线程1读 → 获取读锁线程2读 → 获取读锁（共享）线程3写 → 等待（读写互斥）线程4读 → 获取读锁（新来的读线程可以插队！）线程5读 → 获取读锁...线程3写 → 一直等！写饥饿！解决：ReentrantReadWriteLock默认非公平，改为公平锁new ReentrantReadWriteLock(true)
Synchronized vs ReentrantLock
维度 Synchronized ReentrantLock
实现层面 JVM内置 JUC API
锁获取 自动 手动lock&#x2F;unlock
可中断 不可 lockInterruptibly
超时获取 不支持 tryLock(timeout)
公平性 非公平 公平&#x2F;非公平可选
条件变量 wait&#x2F;notify Condition（多个）
可重入 支持 支持
锁升级 偏向→轻量→重量 无升级机制
异常释放 自动 必须手动unlock
选择建议1. 简单同步 → Synchronized（简洁、JVM优化好）2. 需要可中断 → ReentrantLock3. 需要超时 → ReentrantLock4. 需要公平锁 → ReentrantLock(true)5. 需要多个等待队列 → ReentrantLock + Condition6. 读多写少 → ReentrantReadWriteLock
实战：分布式环境下的本地锁优化// 场景：库存扣减，用本地锁+数据库乐观锁双重保障@Service@RequiredArgsConstructorpublic class StockService &#123; private final ReentrantLock lock = new ReentrantLock(); private final StockMapper stockMapper; public boolean deduct(Long skuId, int quantity) &#123; lock.lock(); try &#123; // 本地锁防止单机并发 Stock stock = stockMapper.selectById(skuId); if (stock.getAvailable() &lt; quantity) &#123; return false; &#125; // 数据库乐观锁防止分布式并发 int rows = stockMapper.deductWithVersion(skuId, quantity, stock.getVersion()); return rows &gt; 0; &#125; finally &#123; lock.unlock(); &#125; &#125;&#125;// Mapper@Update(&quot;UPDATE stock SET available = available - #&#123;quantity&#125;, version = version + 1 &quot; + &quot;WHERE sku_id = #&#123;skuId&#125; AND available &gt;= #&#123;quantity&#125; AND version = #&#123;version&#125;&quot;)int deductWithVersion(@Param(&quot;skuId&quot;) Long skuId, @Param(&quot;quantity&quot;) int quantity, @Param(&quot;version&quot;) int version);
面试高频问题1. Synchronized和ReentrantLock的区别？Synchronized是JVM内置锁，自动获取释放；ReentrantLock是API层面的锁，需要手动获取释放。ReentrantLock功能更丰富：可中断、超时、公平锁、多条件。 2. 什么是锁升级？Synchronized在JDK6后引入锁升级：无锁→偏向锁（单线程）→轻量级锁（CAS自旋）→重量级锁（线程阻塞）。升级不可逆，减少重量级锁的开销。 3. AQS是什么？AbstractQueuedSynchronizer，JUC锁的底层框架。核心是state变量+CLH双向队列。ReentrantLock、ReentrantReadWriteLock、Semaphore、CountDownLatch都基于AQS实现。 最佳实践 简单场景用Synchronized：代码简洁，JVM优化好 高级功能用ReentrantLock：可中断、超时、公平锁 读多写少用ReadWriteLock：读读共享提升并发 永远在finally中释放锁：避免死锁 锁粒度要细：只锁必要的代码块
总结Synchronized和ReentrantLock不是替代关系，而是互补关系。2023年最大的收获是：Synchronized足够简单，ReentrantLock足够灵活，ReadWriteLock适合读多写少。根据场景选择合适的锁，而不是一味追求”高级”。

前言项目中用ThreadLocal存储登录用户信息，线上运行一段时间后内存持续增长。排查发现是ThreadLocal使用不当导致内存泄漏。2023年深入ThreadLocal源码后，终于搞清楚了它的原理和内存泄漏的根因。
ThreadLocal是什么// ThreadLocal：线程本地变量// 每个线程独立拥有一份变量副本，线程间互不影响// 典型场景：存储用户上下文、数据库连接、日期格式化器ThreadLocal&lt;User&gt; currentUser = new ThreadLocal&lt;&gt;();currentUser.set(new User(&quot;张三&quot;));User user = currentUser.get();  // 当前线程获取currentUser.remove();            // 使用完必须清理

底层原理不是Map&lt;Thread, T&gt;，而是Thread持有Map误解：ThreadLocal内部维护一个Map&lt;Thread, T&gt;实际：每个Thread内部维护一个ThreadLocalMap，key是ThreadLocal本身Thread  └── ThreadLocalMap        ├── Entry(threadLocal1, value1)        ├── Entry(threadLocal2, value2)        └── ...好处：线程死亡时，ThreadLocalMap也被GC，不会内存泄漏

源码分析// Thread类中的threadLocals字段public class Thread &#123;    ThreadLocal.ThreadLocalMap threadLocals = null;&#125;// ThreadLocal.set()public void set(T value) &#123;    Thread t = Thread.currentThread();    ThreadLocalMap map = getMap(t);  // 获取当前线程的ThreadLocalMap    if (map != null) &#123;        map.set(this, value);  // key=this(当前ThreadLocal)，value=值    &#125; else &#123;        createMap(t, value);   // 首次创建    &#125;&#125;// ThreadLocal.get()public T get() &#123;    Thread t = Thread.currentThread();    ThreadLocalMap map = getMap(t);    if (map != null) &#123;        ThreadLocalMap.Entry e = map.getEntry(this);  // 用this作为key查找        if (e != null) &#123;            return (T) e.value;        &#125;    &#125;    return setInitialValue();&#125;// ThreadLocalMap是ThreadLocal的静态内部类static class ThreadLocalMap &#123;    static class Entry extends WeakReference&lt;ThreadLocal&lt;?&gt;&gt; &#123;        Object value;  // 注意：value是强引用！        Entry(ThreadLocal&lt;?&gt; k, Object v) &#123;            super(k);  // key是弱引用            value = v;        &#125;    &#125;    private Entry[] table;&#125;

为什么key用弱引用如果key是强引用：ThreadLocal ref = new ThreadLocal&lt;&gt;();ref = null;  // 释放ThreadLocal引用但ThreadLocalMap中的key仍然引用ThreadLocal对象 → GC无法回收 → 内存泄漏key用弱引用后：ThreadLocal ref = new ThreadLocal&lt;&gt;();ref = null;  // 释放引用ThreadLocalMap中的key是弱引用 → GC时回收key → key=null但value仍然是强引用 → value无法回收 → 仍可能内存泄漏！

内存泄漏的完整分析泄漏链路Thread → ThreadLocalMap → Entry                           ├── key(WeakReference) → ThreadLocal对象                           └── value(强引用) → 实际值当ThreadLocal外部引用被释放：1. key被GC回收 → key=null2. value仍然被Entry强引用 → value无法回收3. 如果线程长期存活（线程池）→ value一直无法回收 → 内存泄漏Thread Ref → Thread → ThreadLocalMap → Entry                                    ├── key = null                                    └── value = 大对象 ← 泄漏！

为什么线程池场景更容易泄漏// 线程池中线程复用，不会销毁ExecutorService pool = Executors.newFixedThreadPool(10);pool.execute(() -&gt; &#123;    currentUser.set(new User(&quot;张三&quot;));  // 设置ThreadLocal    // 业务逻辑...    // ❌ 忘记remove()    // 线程回到线程池，ThreadLocalMap中的value不会被清除    // 下次这个线程被复用，ThreadLocalMap中仍然有上次的value&#125;);// 下次复用同一个线程时pool.execute(() -&gt; &#123;    User user = currentUser.get();  // 可能拿到上次残留的值！    // 数据串了！&#125;);

ThreadLocal的自我清理机制// ThreadLocalMap在以下操作时会清理key=null的Entry：// 1. set()时// 2. get()时// expungeStaleEntry：清理过期Entryprivate int expungeStaleEntry(int staleSlot) &#123;    Entry[] tab = table;    int len = tab.length;    // 清理当前slot    tab[staleSlot].value = null;  // 释放value    tab[staleSlot] = null;        // 释放Entry    // 清理其他过期Entry    for (int i = nextIndex(staleSlot, len); ... ) &#123;        Entry e = tab[i];        if (e == null) break;        if (e.get() == null) &#123;  // key=null，过期            e.value = null;            tab[i] = null;        &#125;    &#125;&#125;// 但这个清理不是100%可靠的！// 如果只调用get()且命中的Entry不过期，不会触发清理

正确使用ThreadLocal规则1：使用完必须remove// ✅ 正确用法try &#123;    currentUser.set(user);    // 业务逻辑&#125; finally &#123;    currentUser.remove();  // 必须在finally中清理&#125;

规则2：使用InheritableThreadLocal传递父子线程数据// 普通ThreadLocal：子线程无法获取父线程的值ThreadLocal&lt;String&gt; tl = new ThreadLocal&lt;&gt;();tl.set(&quot;父线程数据&quot;);new Thread(() -&gt; &#123;    tl.get();  // null！子线程获取不到&#125;).start();// InheritableThreadLocal：子线程可以继承父线程的值InheritableThreadLocal&lt;String&gt; itl = new InheritableThreadLocal&lt;&gt;();itl.set(&quot;父线程数据&quot;);new Thread(() -&gt; &#123;    itl.get();  // &quot;父线程数据&quot;&#125;).start();// 但线程池场景下InheritableThreadLocal也不可靠// 因为线程是复用的，不会重新创建，也就不会继承新值

规则3：线程池场景用TransmittableThreadLocal&lt;dependency&gt;    &lt;groupId&gt;com.alibaba&lt;/groupId&gt;    &lt;artifactId&gt;transmittable-thread-local&lt;/artifactId&gt;    &lt;version&gt;2.14.3&lt;/version&gt;&lt;/dependency&gt;

// 阿里开源的TransmittableThreadLocal// 解决线程池场景下ThreadLocal值传递问题TransmittableThreadLocal&lt;String&gt; ttl = new TransmittableThreadLocal&lt;&gt;();ttl.set(&quot;父线程数据&quot;);ExecutorService pool = Executors.newFixedThreadPool(4);// 包装线程池ExecutorService ttlPool = TtlExecutors.getTtlExecutorService(pool);ttlPool.execute(() -&gt; &#123;    ttl.get();  // &quot;父线程数据&quot; ✅&#125;);

实战：用户上下文管理方案1：Filter + ThreadLocal@Componentpublic class UserContextFilter implements Filter &#123;    public static final ThreadLocal&lt;LoginUser&gt; CONTEXT = new ThreadLocal&lt;&gt;();    @Override    public void doFilter(ServletRequest request, ServletResponse response,            FilterChain chain) throws IOException, ServletException &#123;        HttpServletRequest req = (HttpServletRequest) request;        try &#123;            // 从请求头获取用户信息            String token = req.getHeader(&quot;Authorization&quot;);            LoginUser user = tokenService.parseToken(token);            CONTEXT.set(user);            chain.doFilter(request, response);        &#125; finally &#123;            CONTEXT.remove();  // 必须清理！        &#125;    &#125;    public static LoginUser getCurrentUser() &#123;        return CONTEXT.get();    &#125;&#125;

方案2：封装UserContext工具类public class UserContext &#123;    private static final ThreadLocal&lt;LoginUser&gt; CONTEXT = new ThreadLocal&lt;&gt;();    public static void set(LoginUser user) &#123;        CONTEXT.set(user);    &#125;    public static LoginUser get() &#123;        return CONTEXT.get();    &#125;    public static Long getUserId() &#123;        LoginUser user = get();        return user != null ? user.getId() : null;    &#125;    public static void remove() &#123;        CONTEXT.remove();    &#125;&#125;

方案3：Spring Security的SecurityContextHolder// Spring Security内部也用ThreadLocal存储用户信息SecurityContextHolder.getContext().getAuthentication();// 默认策略：MODE_THREADLOCAL// 线程池场景：MODE_INHERITABLETHREADLOCALSecurityContextHolder.setStrategyName(SecurityContextHolder.MODE_INHERITABLETHREADLOCAL);

ThreadLocal的Hash冲突处理// ThreadLocalMap使用开放寻址法（线性探测）解决冲突// 而HashMap使用链地址法// 原因：ThreadLocal数量通常不多，开放寻址法更省内存private void set(ThreadLocal&lt;?&gt; key, Object value) &#123;    Entry[] tab = table;    int len = tab.length;    int i = key.threadLocalHashCode &amp; (len - 1);  // 定位slot    for (Entry e = tab[i]; e != null; e = tab[i = nextIndex(i, len)]) &#123;        ThreadLocal&lt;?&gt; k = e.get();        if (k == key) &#123;           // 找到相同key，更新            e.value = value;            return;        &#125;        if (k == null) &#123;          // 过期Entry，替换            replaceStaleEntry(key, value, i);            return;        &#125;    &#125;    tab[i] = new Entry(key, value);  // 空slot，插入    int sz = ++size;    if (!cleanSomeSlots(i, sz) &amp;&amp; sz &gt;= threshold)        rehash();  // 扩容&#125;// threadLocalHashCode = nextHashCode()// nextHashCode = hashCode + HASH_INCREMENT(0x61c88647)// 这个魔数让hash分布非常均匀

面试高频问题1. ThreadLocal的原理？每个Thread内部维护一个ThreadLocalMap，key是ThreadLocal的弱引用，value是实际值。线程通过ThreadLocal对象作为key从自己的Map中取值。
2. ThreadLocal为什么会内存泄漏？key是弱引用会被GC回收变成null，但value是强引用不会被回收。如果线程长期存活（线程池），value就泄漏了。解决：使用完调用remove()。
3. ThreadLocal和InheritableThreadLocal的区别？InheritableThreadLocal子线程可以继承父线程的值，但在线程池场景不可靠。推荐使用阿里的TransmittableThreadLocal。
最佳实践
使用完必须remove：finally中清理
声明为static final：避免创建过多ThreadLocal实例
线程池场景用TTL：TransmittableThreadLocal
存储轻量对象：不要存大对象
封装工具类：统一管理ThreadLocal的set&#x2F;get&#x2F;remove

总结ThreadLocal是线程隔离的利器，但也是内存泄漏的常见来源。2023年深入源码后，核心认知是：ThreadLocal的key是弱引用但value是强引用，线程池场景必须手动remove否则泄漏。正确使用ThreadLocal的三板斧：try-finally-remove。

前言微服务拆分后，一个业务操作往往涉及多个服务：创建订单要扣库存、扣余额、发积分。本地事务搞不定了，必须引入分布式事务。但分布式事务方案众多——2PC、TCC、SAGA、本地消息表、事务消息——该选哪个？2023年我系统学习了分布式事务的各类方案，形成了清晰的选型思路。 为什么需要分布式事务单体架构：一个事务搞定一切BEGIN; INSERT INTO `order` ...; -- 创建订单 UPDATE stock SET count = count - 1; -- 扣库存 UPDATE account SET balance = balance - 100; -- 扣余额COMMIT;微服务架构：一个操作涉及多个数据库订单服务 → 订单库库存服务 → 库存库账户服务 → 账户库每个服务有自己的数据库，本地事务无法保证跨库一致性！
分布式事务的经典场景1. 跨服务数据一致性 下单 → 扣库存 + 扣余额 + 发积分2. 跨库数据一致性 分库分表后，数据分布在不同的库3. 异步消息一致性 业务操作 + 发送消息必须同时成功或失败4. 补偿一致性 部分操作失败，需要回滚已成功的操作
CAP定理与BASE理论CAP定理：- Consistency（一致性）：所有节点看到相同的数据- Availability（可用性）：每个请求都能得到响应- Partition tolerance（分区容错）：网络分区时系统仍能工作分布式系统只能满足其中两个，通常是AP或CP：- CP：牺牲可用性保证一致性（ZooKeeper、etcd）- AP：牺牲一致性保证可用性（Eureka、Nacos）BASE理论（AP方向的实践）：- Basically Available（基本可用）：允许响应时间增加或功能降级- Soft State（软状态）：允许中间状态- Eventually Consistent（最终一致性）：一段时间后达到一致核心结论：分布式事务无法做到强一致性，只能追求最终一致性
方案一：2PC（两阶段提交）第一阶段：Prepare（准备） 协调者 → 参与者1：准备提交 协调者 → 参与者2：准备提交 参与者1 → 协调者：OK 参与者2 → 协调者：OK第二阶段：Commit/Rollback（提交/回滚） 协调者 → 参与者1：提交 协调者 → 参与者2：提交问题：1. 同步阻塞：所有参与者锁定资源直到提交2. 单点故障：协调者挂了，参与者永远阻塞3. 数据不一致：第二阶段部分参与者提交失败4. 太保守：任意一个参与者超时，整个事务回滚
Seata AT模式（2PC的优化实现）&lt;dependency&gt; &lt;groupId&gt;com.alibaba.cloud&lt;/groupId&gt; &lt;artifactId&gt;spring-cloud-starter-alibaba-seata&lt;/artifactId&gt;&lt;/dependency&gt;
# Seata配置seata: enabled: true application-id: order-service tx-service-group: my-tx-group service: vgroup-mapping: my-tx-group: default registry: type: nacos nacos: server-addr: localhost:8848 namespace: seata
// 使用@GlobalTransactional注解@Servicepublic class OrderService &#123; @GlobalTransactional(name = &quot;create-order&quot;, rollbackFor = Exception.class) public void createOrder(OrderDTO orderDTO) &#123; // 1. 创建订单 orderMapper.insert(order); // 2. 扣库存（远程调用） stockFeignClient.deduct(orderDTO.getProductId(), orderDTO.getQuantity()); // 3. 扣余额（远程调用） accountFeignClient.deduct(orderDTO.getUserId(), orderDTO.getAmount()); // 任意一步失败，全局回滚 &#125;&#125;
Seata AT模式工作原理：1. 一阶段：拦截SQL，生成前镜像和后镜像，写入undo_log表2. 二阶段提交：异步删除undo_log3. 二阶段回滚：根据undo_log的前镜像反向补偿优点：对业务无侵入，只需加注解缺点：需要undo_log表，全局锁可能影响性能
方案二：TCC（Try-Confirm-Cancel）// TCC模式：每个操作需要实现三个方法public interface StockTccService &#123; /** * Try：预留资源（冻结库存） */ boolean tryDeduct(Long productId, Integer quantity); /** * Confirm：确认扣减（真正扣减） */ boolean confirmDeduct(Long productId, Integer quantity); /** * Cancel：取消预留（解冻库存） */ boolean cancelDeduct(Long productId, Integer quantity);&#125;@Service@Slf4jpublic class StockTccServiceImpl implements StockTccService &#123; @Autowired private StockMapper stockMapper; @Override @Transactional public boolean tryDeduct(Long productId, Integer quantity) &#123; log.info(&quot;Try: 冻结库存 productId=&#123;&#125;, quantity=&#123;&#125;&quot;, productId, quantity); // 冻结库存：将库存移到冻结字段 int rows = stockMapper.freezeStock(productId, quantity); return rows &gt; 0; &#125; @Override @Transactional public boolean confirmDeduct(Long productId, Integer quantity) &#123; log.info(&quot;Confirm: 确认扣减 productId=&#123;&#125;, quantity=&#123;&#125;&quot;, productId, quantity); // 真正扣减：从冻结字段中减去 int rows = stockMapper.deductFrozenStock(productId, quantity); return rows &gt; 0; &#125; @Override @Transactional public boolean cancelDeduct(Long productId, Integer quantity) &#123; log.info(&quot;Cancel: 解冻库存 productId=&#123;&#125;, quantity=&#123;&#125;&quot;, productId, quantity); // 解冻：将冻结的库存移回可用字段 int rows = stockMapper.unfreezeStock(productId, quantity); return rows &gt; 0; &#125;&#125;
-- 库存表设计（支持TCC）CREATE TABLE `stock` ( `id` bigint NOT NULL AUTO_INCREMENT, `product_id` bigint NOT NULL, `available` int NOT NULL DEFAULT 0 COMMENT &#x27;可用库存&#x27;, `frozen` int NOT NULL DEFAULT 0 COMMENT &#x27;冻结库存&#x27;, PRIMARY KEY (`id`), UNIQUE KEY `uk_product_id` (`product_id`)) ENGINE=InnoDB;-- 冻结库存UPDATE stock SET available = available - #&#123;quantity&#125;, frozen = frozen + #&#123;quantity&#125;WHERE product_id = #&#123;productId&#125; AND available &gt;= #&#123;quantity&#125;;-- 确认扣减UPDATE stock SET frozen = frozen - #&#123;quantity&#125;WHERE product_id = #&#123;productId&#125;;-- 解冻库存UPDATE stock SET available = available + #&#123;quantity&#125;, frozen = frozen - #&#123;quantity&#125;WHERE product_id = #&#123;productId&#125;;
TCC优缺点：优点：- 性能好，不锁资源（Try阶段就完成了资源预留）- 对数据库无侵入缺点：- 实现复杂，每个操作要写三个方法- Try/Confirm/Cancel必须幂等- 需要处理空回滚、悬挂等异常场景
方案三：本地消息表-- 本地消息表CREATE TABLE `local_message` ( `id` bigint NOT NULL AUTO_INCREMENT, `message_id` varchar(64) NOT NULL COMMENT &#x27;消息唯一ID&#x27;, `content` text NOT NULL COMMENT &#x27;消息内容&#x27;, `status` tinyint NOT NULL DEFAULT 0 COMMENT &#x27;0-待发送 1-已发送 2-已消费 3-失败&#x27;, `retry_count` int NOT NULL DEFAULT 0 COMMENT &#x27;重试次数&#x27;, `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP, `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, PRIMARY KEY (`id`), UNIQUE KEY `uk_message_id` (`message_id`)) ENGINE=InnoDB;
@Service@RequiredArgsConstructor@Slf4jpublic class OrderService &#123; private final OrderMapper orderMapper; private final LocalMessageMapper localMessageMapper; private final RabbitTemplate rabbitTemplate; /** * 创建订单 + 发送消息（本地消息表方案） */ @Transactional(rollbackFor = Exception.class) public void createOrder(OrderDTO orderDTO) &#123; // 1. 业务操作：创建订单 Order order = new Order(); // ... 设置属性 orderMapper.insert(order); // 2. 写入本地消息表（与业务在同一事务中） LocalMessage message = new LocalMessage(); message.setMessageId(IdUtil.simpleUUID()); message.setContent(JSON.toJSONString(orderDTO)); message.setStatus(0); // 待发送 localMessageMapper.insert(message); &#125; /** * 定时任务：扫描未发送的消息 */ @Scheduled(fixedRate = 5000) public void sendPendingMessages() &#123; List&lt;LocalMessage&gt; messages = localMessageMapper.selectByStatus(0); for (LocalMessage message : messages) &#123; try &#123; rabbitTemplate.convertAndSend(&quot;order.exchange&quot;, &quot;order.created&quot;, message.getContent()); message.setStatus(1); // 已发送 localMessageMapper.updateById(message); &#125; catch (Exception e) &#123; message.setRetryCount(message.getRetryCount() + 1); if (message.getRetryCount() &gt;= 5) &#123; message.setStatus(3); // 失败 &#125; localMessageMapper.updateById(message); log.error(&quot;消息发送失败: messageId=&#123;&#125;&quot;, message.getMessageId(), e); &#125; &#125; &#125;&#125;
方案四：SAGA模式SAGA模式：将长事务拆分为多个本地短事务，每个事务有对应的补偿操作正向执行：T1(创建订单) → T2(扣库存) → T3(扣余额) → 完成异常补偿：T1(创建订单) → T2(扣库存) → T3(扣余额失败) ↓ C2(恢复库存) ← C1(取消订单)适用场景：- 业务流程长- 参与者多- 允许最终一致性
方案对比与选型
方案 一致性 性能 侵入性 复杂度 适用场景
2PC&#x2F;Seata AT 强一致 中 低 低 短事务、对一致性要求高
TCC 强一致 高 高 高 资源预留型业务
本地消息表 最终一致 高 中 中 异步场景、对实时性要求低
事务消息 最终一致 高 中 中 MQ场景、RocketMQ原生支持
SAGA 最终一致 高 中 高 长流程、多参与者
选型建议1. 大多数场景：Seata AT模式 对业务无侵入，加个注解就行 适合90%的分布式事务场景2. 高性能场景：TCC 性能要求高，可以接受实现复杂度 适合库存、余额等资源预留型业务3. 异步场景：本地消息表/事务消息 不需要实时一致性 适合通知、积分、日志等非核心业务4. 长流程场景：SAGA 业务流程长，参与者多 适合跨公司、跨系统的业务编排
分布式事务注意事项1. 能不用就不用 合理的服务拆分，减少跨服务事务 将关联数据放在同一个服务中2. 追求最终一致性 大多数业务场景不需要强一致 最终一致性足够且性能更好3. 幂等性是前提 所有参与者必须保证操作幂等 网络重试、补偿重试都可能重复执行4. 补偿操作必须安全 补偿操作不能失败 补偿操作本身也需要重试机制5. 监控告警 事务失败必须有告警 人工介入处理异常情况
总结分布式事务没有银弹，核心是在一致性和性能之间做取舍。强一致性选2PC&#x2F;TCC，最终一致性选本地消息表&#x2F;事务消息&#x2F;SAGA。实际项目中，大多数场景用Seata AT模式就够了，非核心业务用消息队列实现最终一致性。记住：最好的分布式事务是不需要分布式事务——合理的服务拆分和数据设计，才是根本解决方案。

前言线上一个订单详情接口响应时间2秒，用户频繁投诉。排查后发现不是单一问题，而是多个小问题叠加：慢SQL、串行调用、冗余查询、无缓存。优化后降到50ms，这次经历让我形成了接口性能优化的完整方法论。
性能优化方法论接口性能优化四步法：1. 定位瓶颈 → 哪里慢？2. 分析原因 → 为什么慢？3. 选择方案 → 怎么优化？4. 验证效果 → 优化了多少？定位瓶颈的工具：- Arthas trace：方法级耗时- MySQL EXPLAIN：SQL执行计划- 浏览器Network：接口耗时分布- SkyWalking：全链路追踪

优化一：慢SQL优化问题// 订单详情接口，耗时1.5秒@GetMapping(&quot;/order/&#123;id&#125;&quot;)public OrderVO getOrderDetail(@PathVariable Long id) &#123;    return orderService.getOrderDetail(id);&#125;

-- 慢SQL1：订单基本信息查询SELECT * FROM `order` WHERE order_no = &#x27;ORD202306010001&#x27;;-- 耗时800ms，走全表扫描-- 慢SQL2：订单商品查询SELECT * FROM order_item WHERE order_id = 12345;-- 耗时300ms，order_id没有索引-- 慢SQL3：商品信息查询（N+1问题）SELECT * FROM product WHERE id = 1001;  -- 循环调用SELECT * FROM product WHERE id = 1002;SELECT * FROM product WHERE id = 1003;-- 耗时400ms，3次数据库查询

优化-- 优化1：给order_no加索引ALTER TABLE `order` ADD INDEX idx_order_no(order_no);-- 800ms → 5ms-- 优化2：给order_id加索引ALTER TABLE order_item ADD INDEX idx_order_id(order_id);-- 300ms → 3ms-- 优化3：批量查询替代N+1SELECT * FROM product WHERE id IN (1001, 1002, 1003);-- 400ms → 5ms

// 优化后的代码public OrderVO getOrderDetail(Long id) &#123;    // 1. 查询订单基本信息（走索引）    Order order = orderMapper.selectByOrderNo(orderNo);    // 2. 查询订单商品（走索引）    List&lt;OrderItem&gt; items = orderItemMapper.selectByOrderId(order.getId());    // 3. 批量查询商品信息（替代N+1）    List&lt;Long&gt; productIds = items.stream()        .map(OrderItem::getProductId)        .distinct()        .collect(Collectors.toList());    List&lt;Product&gt; products = productMapper.selectBatchIds(productIds);    Map&lt;Long, Product&gt; productMap = products.stream()        .collect(Collectors.toMap(Product::getId, Function.identity()));    // 4. 组装返回    return buildOrderVO(order, items, productMap);&#125;

优化二：缓存优化问题// 每次请求都查数据库，热点数据重复查询public Product getProduct(Long productId) &#123;    return productMapper.selectById(productId);    // 商品信息变更频率低，完全可以缓存&#125;

优化@Service@RequiredArgsConstructorpublic class ProductService &#123;    private final ProductMapper productMapper;    private final StringRedisTemplate redisTemplate;    private static final String PRODUCT_KEY = &quot;product:detail:&quot;;    private static final long CACHE_TTL = 30; // 分钟    /**     * 缓存优化：先查缓存，再查数据库     */    public Product getProduct(Long productId) &#123;        String key = PRODUCT_KEY + productId;        // 1. 查缓存        String cache = redisTemplate.opsForValue().get(key);        if (StrUtil.isNotBlank(cache)) &#123;            return JSON.parseObject(cache, Product.class);        &#125;        // 2. 查数据库        Product product = productMapper.selectById(productId);        if (product == null) &#123;            // 防止缓存穿透：缓存空值            redisTemplate.opsForValue().set(key, &quot;&quot;, 5, TimeUnit.MINUTES);            return null;        &#125;        // 3. 写入缓存        redisTemplate.opsForValue().set(key,             JSON.toJSONString(product), CACHE_TTL, TimeUnit.MINUTES);        return product;    &#125;&#125;

优化三：并行调用问题// 串行调用多个服务，总耗时 = 所有服务耗时之和public OrderVO getOrderDetail(Long id) &#123;    Order order = orderMapper.selectById(id);          // 50ms    List&lt;OrderItem&gt; items = orderItemMapper.selectByOrderId(id);  // 30ms    User user = userService.getById(order.getUserId());           // 100ms    Logistics logistics = logisticsService.getByOrderId(id);      // 80ms    // 总耗时：50 + 30 + 100 + 80 = 260ms&#125;

优化@Service@RequiredArgsConstructorpublic class OrderService &#123;    private final OrderMapper orderMapper;    private final OrderItemMapper orderItemMapper;    private final UserService userService;    private final LogisticsService logisticsService;    @Autowired    @Qualifier(&quot;orderThreadPool&quot;)    private ThreadPoolExecutor threadPool;    /**     * 并行调用优化：互不依赖的调用并行执行     */    public OrderVO getOrderDetail(Long id) &#123;        // 第一步：先查订单（后续查询依赖订单数据）        Order order = orderMapper.selectById(id);  // 50ms        // 第二步：并行查询互不依赖的数据        CompletableFuture&lt;List&lt;OrderItem&gt;&gt; itemsFuture = CompletableFuture            .supplyAsync(() -&gt; orderItemMapper.selectByOrderId(id), threadPool);        CompletableFuture&lt;User&gt; userFuture = CompletableFuture            .supplyAsync(() -&gt; userService.getById(order.getUserId()), threadPool);        CompletableFuture&lt;Logistics&gt; logisticsFuture = CompletableFuture            .supplyAsync(() -&gt; logisticsService.getByOrderId(id), threadPool);        // 等待所有结果        CompletableFuture.allOf(itemsFuture, userFuture, logisticsFuture).join();        List&lt;OrderItem&gt; items = itemsFuture.join();        User user = userFuture.join();        Logistics logistics = logisticsFuture.join();        // 总耗时：50 + max(30, 100, 80) = 50 + 100 = 150ms        return buildOrderVO(order, items, user, logistics);    &#125;&#125;

优化四：冗余查询消除问题// 同一个请求中多次查询相同的用户信息public void processOrder(OrderDTO dto) &#123;    // 第1次查用户    User user = userService.getById(dto.getUserId());    // 第2次查用户（在validate方法中）    validateOrder(dto);  // 内部又查了一次用户    // 第3次查用户（在sendNotify方法中）    sendNotify(dto);     // 内部又查了一次用户&#125;

优化// 查询一次，参数传递public void processOrder(OrderDTO dto) &#123;    User user = userService.getById(dto.getUserId());    validateOrder(dto, user);    // 传递user参数    sendNotify(dto, user);       // 传递user参数&#125;// 或者使用ThreadLocal/RequestScope缓存@Component@Scope(value = WebApplicationContext.SCOPE_REQUEST, proxyMode = ScopedProxyMode.TARGET_CLASS)public class UserContext &#123;    private Map&lt;Long, User&gt; userCache = new HashMap&lt;&gt;();    public User getUser(Long userId) &#123;        return userCache.computeIfAbsent(userId,             id -&gt; userService.getById(id));    &#125;&#125;

优化五：批量操作优化问题// 循环单条插入，1000条数据 = 1000次数据库交互public void batchInsert(List&lt;OrderItem&gt; items) &#123;    for (OrderItem item : items) &#123;        orderItemMapper.insert(item);  // 每次一条SQL    &#125;    // 1000条 × 5ms = 5000ms&#125;

优化// 方案1：MyBatis批量插入public void batchInsert(List&lt;OrderItem&gt; items) &#123;    orderItemMapper.batchInsert(items);    // 1次SQL，耗时约50ms&#125;// 方案2：分批插入（数据量大时）public void batchInsert(List&lt;OrderItem&gt; items) &#123;    List&lt;List&lt;OrderItem&gt;&gt; partitions = Lists.partition(items, 500);    for (List&lt;OrderItem&gt; partition : partitions) &#123;        orderItemMapper.batchInsert(partition);    &#125;&#125;

&lt;!-- Mapper XML --&gt;&lt;insert id=&quot;batchInsert&quot;&gt;    INSERT INTO order_item (order_id, product_id, quantity, price)    VALUES    &lt;foreach collection=&quot;list&quot; item=&quot;item&quot; separator=&quot;,&quot;&gt;        (#&#123;item.orderId&#125;, #&#123;item.productId&#125;, #&#123;item.quantity&#125;, #&#123;item.price&#125;)    &lt;/foreach&gt;&lt;/insert&gt;

优化六：异步化问题// 同步执行非核心逻辑，拖慢接口响应public void createOrder(OrderDTO dto) &#123;    orderMapper.insert(order);           // 核心逻辑：50ms    couponService.useCoupon(dto);        // 非核心：100ms    pointsService.addPoints(dto);        // 非核心：80ms    smsService.sendNotify(dto);          // 非核心：200ms    // 总耗时：50 + 100 + 80 + 200 = 430ms&#125;

优化public void createOrder(OrderDTO dto) &#123;    // 核心逻辑同步执行    orderMapper.insert(order);           // 50ms    // 非核心逻辑异步执行    CompletableFuture.runAsync(() -&gt; couponService.useCoupon(dto), threadPool);    CompletableFuture.runAsync(() -&gt; pointsService.addPoints(dto), threadPool);    CompletableFuture.runAsync(() -&gt; smsService.sendNotify(dto), threadPool);    // 总耗时：50ms（核心逻辑完成即返回）&#125;// 或者使用消息队列异步化public void createOrder(OrderDTO dto) &#123;    orderMapper.insert(order);    // 发送消息，异步处理    rabbitTemplate.convertAndSend(&quot;order.exchange&quot;, &quot;order.created&quot;, dto);&#125;

优化七：压缩响应// 开启GZIP压缩，减少网络传输时间@Configurationpublic class CompressionConfig &#123;    @Bean    public FilterRegistrationBean&lt;GzipFilter&gt; gzipFilter() &#123;        FilterRegistrationBean&lt;GzipFilter&gt; registration = new FilterRegistrationBean&lt;&gt;();        registration.setFilter(new GzipFilter());        registration.addUrlPatterns(&quot;/*&quot;);        return registration;    &#125;&#125;// 或在application.yml中配置server:  compression:    enabled: true    mime-types: application/json,text/html,text/xml,text/plain    min-response-size: 1024  # 超过1KB才压缩

性能优化效果汇总优化前：2000ms├── 慢SQL（无索引）     800ms → 加索引后 5ms├── N+1查询            400ms → 批量查询 5ms├── 无缓存重复查询      300ms → Redis缓存 3ms├── 串行调用           260ms → 并行调用 150ms├── 循环单条操作        200ms → 批量操作 50ms└── 同步非核心逻辑      380ms → 异步化 0ms优化后：50ms提升：40倍

